function doubleNumber(num) {
  // 引数として渡された数値を2倍にします。
  return num * 2;
}

console.log(doubleNumber(5));
// 出力: 10

function sumNumbers(num1, num2) {
  // 引数として渡された二つの数値の和を計算します。
  return num1 + num2;
}

console.log(sumNumbers(3, 4));
// 出力: 7

function greet(name) {
  // 引数として渡された名前を使用してメッセージを作成します。
  return 'Hello, ' + name + '!';
}

console.log(greet('YourName'));
// 出力: Hello, YourName!

function checkScope() {
  // 関数内で変数を定義します。
  var innerVar = 'I am inside!';
  console.log(innerVar);
}

checkScope();
// 出力: I am inside!
console.log(innerVar);
// エラー: innerVar is not defined

function multiplyByTwo(x) {
  // xはパラメーターで、関数が呼び出されるときに値が割り当てられます。
  return x * 2;
}

console.log(multiplyByTwo(5));
// 出力: 10

function greet(name = 'World') {
  // name に引数が渡されなかった場合、デフォルト値として 'World' が使用されます。
  return 'Hello, ' + name + '!';
}

console.log(greet());
// 出力: Hello, World!

function multiply(a, b) {
  // aとbはパラメーターで、関数が呼び出されるときに値が割り当てられます。
  return a * b;
}

console.log(multiply(4, 5));
// 出力: 20

function test() {
  var x = 10;
  console.log(x);
}

test();
// 出力: 10
console.log(x);
// ReferenceError: x is not defined

var x = 'global'; // グローバル変数

function test() {
  var x = 'local'; // ローカル変数
  console.log(x);
}

test();
// 出力: local
console.log(x);
// 出力: global

function sumTo(n) {
  // nが1の場合は、再帰を終了し、1を返します。
  if (n === 1) {
    return 1;
  }
  // それ以外の場合は、nと、n-1までの総和を返します。
  return n + sumTo(n - 1);
}

console.log(sumTo(5));
// 出力: 15 (1+2+3+4+5)

function add(a = 0, b = 0) {
  // aとbの合計を返す
  return a + b;
}

console.log(add(5));
// 出力: 5 (5 + 0)
console.log(add());
// 出力: 0 (0 + 0)

function test(a = 1, b = 2) {
  // aとbを再代入
  a = 3;
  b = 4;
  console.log(a + b);
}

test();
// 出力: 7 (3 + 4)

let subtract = (a, b) => {
  // aとbの差を返す
  return a - b;
};

console.log(subtract(10, 5));
// 出力: 5 (10 - 5)

