アロー関数では、thisの扱いが通常のfunctionと異なります。以下のコードを完成させて、アロー関数内とfunction内でのthisの違いを確認してみてください。

let obj = {
  value: 10,
  arrowFunction: function() {
    let arrow = () => {
      // ここでのthis.valueを出力
    };
    arrow();
  },
  regularFunction: function() {
    function innerFunction() {
      // ここでのthis.valueを出力
    }
    innerFunction();
  }
};
obj.arrowFunction();
obj.regularFunction();

questions.answer:
let obj = {
  value: 10,
  arrowFunction: function() {
    let arrow = () => {
      // ここでのthis.valueを出力
      console.log(this.value);
    };
    arrow();
  },
  regularFunction: function() {
    function innerFunction() {
      // ここでのthis.valueを出力
      console.log(this.value);
    }
    innerFunction();
  }
};
obj.arrowFunction();
// 出力: 10
obj.regularFunction();
// 出力: undefined

(function() {
  // 即時関数の内部
  let x = 10;
  console.log(x);
})();
// 出力: 10

console.log(typeof x);
// 出力: 'undefined', 変数xは即時関数のスコープ内でしか存在しないため

function createCounter() {
  let count = 0;
  return function() {
    // 外部スコープのcount変数を参照し、その値を増加させる
    return ++count;
  };
}

let counter = createCounter();

console.log(counter());
// 出力: 1
console.log(counter());
// 出力: 2, counter関数はcount変数を「記憶」している

function greet() {
  return 'Hello, World!';
}

function shout(func) {
  // 引数として受け取った関数を実行し、その結果を大文字にして返す
  let message = func();
  return message.toUpperCase();
}

console.log(shout(greet));
// 出力: 'HELLO, WORLD!', greet関数の結果を大文字に変換

function greet(name = 'World') {
  // nameパラメータが与えられない場合、デフォルト値'World'が使用される
  return `Hello, ${name}!`;
}

console.log(greet());
// 出力: 'Hello, World!'
console.log(greet('Alice'));
// 出力: 'Hello, Alice!', 引数が与えられた場合、デフォルト値は無視される

let greet = () => {
  // アロー関数の記述
  return 'Hello, World!';
};

console.log(greet());
// 出力: 'Hello, World!'

(function () {
  // 即時関数の記述
  let name = 'Alice';
  console.log(`Hello, ${name}!`);
})();
// 出力: 'Hello, Alice!', 定義と同時に関数が実行される
